pragma solidity ^0.8.20;

contract CollectibleSale {
    address public owner;
    uint256 public maxSupply;
    uint256 public price;
    uint256 public totalMinted;
    bool public saleEnded;
    mapping(address => uint256) private _balances;

    event Bought(address indexed buyer, uint256 amount);
    event PriceSet(uint256 newPrice);
    event Withdrawn(uint256 amount);

    constructor(uint256 maxSupply_, uint256 price_) {
        owner = msg.sender;
        maxSupply = maxSupply_;
        price = price_;
        saleEnded = false;
    }

    function buy(uint256 amount) external payable {
        require(!saleEnded, "Sale has ended");
        require(amount > 0, "Amount must be greater than 0");
        require(amount <= 10, "Amount exceeds limit per transaction");
        require(totalMinted + amount <= maxSupply, "Exceeds max supply");
        require(msg.value == amount * price, "Exact payment required");

        _balances[msg.sender] += amount;
        totalMinted += amount;

        if (totalMinted >= maxSupply) {
            saleEnded = true;
        }

        emit Bought(msg.sender, amount);
    }

    function setPrice(uint256 newPrice) external onlyOwner {
        price = newPrice;
        emit PriceSet(newPrice);
    }

    function withdraw() external onlyOwner {
        require(address(this).balance > 0, "No funds to withdraw");
        uint256 balanceBefore = address(this).balance;
        (bool success,) = payable(owner).call{value: balanceBefore}("");
        require(success, "Transfer failed");
        emit Withdrawn(balanceBefore);
    }

    function balances(address account) public view returns (uint256) {
        return _balances[account];
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not the owner");
        _;
    }

    // Edge case handling: Refund any excess Ether sent
    receive() external payable {
        if (msg.sender != tx.origin) {
            revert("No contract purchases allowed");
        }
    }
}
